  4	import { humanizeBinaryBytes } from '@odf/shared/utils';
  5	import {
  6	  RedExclamationCircleIcon,
  7	  YellowExclamationTriangleIcon,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import { t_global_color_status_danger_default as globalDanger100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 10	import { t_global_text_color_disabled as globalDisable100 } from '@patternfly/react-tokens/dist/js/t_global_text_color_disabled';
 11	import { t_global_color_status_info_default as globalInfo100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_info_default';
 12	import { t_global_color_status_warning_default as globalWarning100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_warning_default';
 13	import classNames from 'classnames';
 14	import { ChartDonut, ChartLabel } from '@patternfly/react-charts';
 15	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 16	import { DANGER_THRESHOLD, WARNING_THRESHOLD } from '../../../constants';
 17	import './capacity-card.scss';
 18	
 19	const generalColorScale = [globalInfo100.value, globalDisable100.value];
 20	const warningColorScale = [globalWarning100.value, globalDisable100.value];
 21	const dangerColorScale = [globalDanger100.value, globalDisable100.value];
 22	
 23	const CapacityStatusIcon: React.FC<CapacityStatusIconProps> = React.memo(
 24	  ({ ratio, warningThreshold, dangerThreshold }) => {
 25	    const { t } = useCustomTranslation();
 26	
 27	    const warnThreshold = warningThreshold ?? WARNING_THRESHOLD;
 28	    const dangerThresh = dangerThreshold ?? DANGER_THRESHOLD;
 29	
 30	    if (ratio < warnThreshold) return null;
 31	    return (
 32	      <>
 33	        {ratio >= dangerThresh && (
 34	          <RedExclamationCircleIcon title={t('Error')} />
 35	        )}
 36	        {ratio >= warnThreshold && ratio < dangerThresh && (
 37	          <YellowExclamationTriangleIcon title={t('Warning')} />
 38	        )}
 39	      </>
 40	    );
 41	  }
 42	);
 43	
 44	CapacityStatusIcon.displayName = 'CapacityStatusIcon';
 45	
 46	// Generic capacity card
 47	export const CapacityCard: React.FC<CapacityCardProps> = React.memo((props) => {
 48	  const {
 49	    totalCapacityMetric,
 50	    availableCapacityMetric,
 51	    usedCapacityMetric,
 52	    description,
 53	    loadError,
 54	    loading,
 55	    warningThreshold,
 56	    dangerThreshold,
 57	  } = props;
 58	  const { t } = useCustomTranslation();
 59	
 60	  const totalCapacity = humanizeBinaryBytes(totalCapacityMetric);
 61	  const availableCapacity = humanizeBinaryBytes(
 62	    availableCapacityMetric,
 63	    null,
 64	    totalCapacity?.unit
 65	  );
 66	  const usedCapacity = humanizeBinaryBytes(
 67	    usedCapacityMetric,
 68	    null,
 69	    totalCapacity?.unit
 70	  );
 71	
 72	  // Adjusted units
 73	  const usedCapacityAdjusted = humanizeBinaryBytes(usedCapacityMetric);
 74	  const availableCapacityAdjusted = humanizeBinaryBytes(
 75	    totalCapacityMetric - usedCapacityMetric
 76	  );
 77	  const capacityRatio = parseFloat(
 78	    (usedCapacity.value / totalCapacity.value).toFixed(2)
 79	  );
 80	
 81	  const colorScale = React.useMemo(() => {
 82	    const warnThreshold = warningThreshold ?? WARNING_THRESHOLD;
 83	    const dangerThresh = dangerThreshold ?? DANGER_THRESHOLD;
 84	
 85	    if (capacityRatio >= dangerThresh) return dangerColorScale;
 86	    if (capacityRatio >= warnThreshold && capacityRatio < dangerThresh)
 87	      return warningColorScale;
 88	    return generalColorScale;
 89	  }, [capacityRatio, warningThreshold, dangerThreshold]);
 90	
 91	  const donutData = [
 92	    { x: 'Used', y: usedCapacity.value, string: usedCapacityAdjusted.string },
 93	    {
 94	      x: 'Available',
 95	      y: availableCapacity.value,
 96	      string: availableCapacityAdjusted.string,
 97	    },
 98	  ];
 99	
100	  return (
101	    <Card>
102	      <CardHeader>
103	        <CardTitle>
104	          {t('Raw capacity')}
105	          <FieldLevelHelp>{description}</FieldLevelHelp>
106	        </CardTitle>
107	      </CardHeader>
108	      <CardBody className="ceph-raw-usage__container">
109	        {!loading && !loadError && (
110	          <>
111	            <div className="ceph-raw-usage__item ceph-raw-usage__legend">
112	              <ChartLegend
113	                fill={colorScale[0]}
114	                title={t('Used')}
115	                text={usedCapacityAdjusted.string}
116	                titleClassName="ceph-raw-card-legend__title--pad"
117	              />
118	              <ChartLegend
119	                fill={colorScale[1]}
120	                title={t('Available')}
121	                text={availableCapacityAdjusted.string}
122	                capacityStatus={
123	                  <CapacityStatusIcon
124	                    ratio={capacityRatio}
125	                    warningThreshold={warningThreshold}
126	                    dangerThreshold={dangerThreshold}
127	                  />
128	                }
129	              />
130	            </div>
131	            <div className="ceph-raw-usage__item ceph-raw-usage__chart">
132	              <ChartDonut
133	                ariaDesc={t('Available versus Used Capacity')}
134	                ariaTitle={t('Available versus Used Capacity')}
135	                height={150}
136	                width={150}
137	                data={donutData}
138	                labels={({ datum }) => `${datum.string}`}
139	                title={usedCapacityAdjusted.string}
140	                subTitle={t('Used of {{capacity}}', {
141	                  capacity: totalCapacity.string,
142	                })}
143	                colorScale={colorScale}
144	                padding={{ top: 0, bottom: 0, left: 0, right: 0 }}
145	                constrainToVisibleArea
146	                titleComponent={
147	                  <ChartLabel
148	                    style={{ fill: `var(--pf-t--global--text--color--regular)` }}
149	                  />
150	                }
151	                subTitleComponent={
152	                  <ChartLabel
153	                    dy={5}
154	                    style={{ fill: `var(--pf-t--global--text--color--subtle)` }}
155	                  />
156	                }
157	              />
158	            </div>
159	          </>
160	        )}
161	        {loading && !loadError && <LoadingCardBody />}
162	        {loadError && <ErrorCardBody />}
163	      </CardBody>
164	    </Card>
165	  );
166	});
167	
