169	  <div>
170	    <div className="ceph-raw-usage-loading__legend">
171	      <div className="ceph-raw-usage-loading-legend__item skeleton-activity" />
172	      <div className="ceph-raw-usage-loading-legend__item skeleton-activity" />
173	    </div>
174	    <div className="ceph-raw-usage-loading__chart skeleton-activity" />
175	  </div>
176	);
