186	  fill,
187	  title,
188	  text,
189	  titleClassName,
190	  capacityStatus,
191	}) => {
192	  return (
193	    <div className="ceph-raw-card-legend__container">
194	      <div className="ceph-raw-card-legend__index-block">
195	        <div
196	          className="ceph-raw-card-legend__color-square"
197	          style={{ backgroundColor: fill }}
198	        />
199	        <div
200	          className={classNames('ceph-raw-card-legend__title', titleClassName)}
201	        >
202	          {title}
203	        </div>
204	      </div>
205	      <div className="ceph-raw-card-legend__value-block">
206	        <div className="ceph-raw-card-legend__text">{text}</div>
207	      </div>
208	      {capacityStatus && (
209	        <div className="ceph-raw-card-legend__icon-block">{capacityStatus}</div>
210	      )}
211	    </div>
212	  );
213	};
